import React, { useState } from 'react';
import { Image, View, Text, TouchableOpacity } from 'react-native';
import { router } from 'expo-router';
import { useTheme } from '@/theme';
import { spacing, borderRadius, fontSize } from '@/theme/tokens';
import { Screen } from '@/components/ScreenComponents';
import { Button, TextInput } from '@/components/BaseComponents';
import { useAuth } from '@/hooks/useAuth';
import { Eye, EyeOff, User, Mail, Phone, Lock } from 'lucide-react-native';
import { isValidEmail, toVietnameseAuthError, validatePassword } from '@/utils/authValidation';
import { DAIGO_LOGO_URL } from '@/constants/branding';
import { showError as showErrorToast, showInfo, showSuccess } from '@/utils/toast';

export default function RegisterScreen() {
  const { colors } = useTheme();
  const { register, isLoading, error } = useAuth();

  const [fullName, setFullName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [localError, setLocalError] = useState('');

  const showError = (message: string) => {
    setLocalError(message);
    showErrorToast('Không thể đăng ký', message);
  };

  const handleRegister = async () => {
    if (!fullName || !email || !phone || !password || !confirmPassword) {
      showError('Vui lòng nhập đầy đủ họ tên, email, số điện thoại và mật khẩu.');
      return;
    }

    if (fullName.trim().length < 2) {
      showError('Họ và tên phải có ít nhất 2 ký tự.');
      return;
    }

    if (!isValidEmail(email)) {
      showError('Email không đúng định dạng.');
      return;
    }

    if (phone.trim().length < 9) {
      showError('Số điện thoại không hợp lệ.');
      return;
    }

    const passwordError = validatePassword(password);
    if (passwordError) {
      showError(passwordError);
      return;
    }

    if (password !== confirmPassword) {
      showError('Mật khẩu xác nhận không khớp.');
      return;
    }

    try {
      const response = await register({
        fullName,
        email,
        phone,
        password,
        confirmPassword,
      });
      if (response.token) {
        router.replace(response.user.role === 'driver' ? '/(driver)/dashboard' : '/(customer)/home');
        showSuccess('Đăng ký thành công', `Tài khoản ${response.user.fullName} đã sẵn sàng.`);
      } else {
        showInfo('Xác thực email', 'Tài khoản đã được tạo. Vui lòng nhập mã OTP được gửi về email để kích hoạt tài khoản.');
        router.replace({
          pathname: '/(auth)/verify-email' as any,
          params: { email },
        });
      }
    } catch (err: any) {
      showError(toVietnameseAuthError(err.message));
    }
  };

  return (
    <Screen scroll padding>
      {/* ─── LOGO COMPACT HEADER ─── */}
      <View
        style={{
          alignItems: 'center',
          paddingTop: spacing.md,
          paddingBottom: spacing.xl,
        }}
      >
        <Image
          source={{ uri: DAIGO_LOGO_URL }}
          style={{
            width: 130,
            height: 56,
            resizeMode: 'contain',
          }}
        />
      </View>

      <Text
        style={{
          fontSize: 24,
          fontWeight: '800',
          color: colors.text,
          marginBottom: spacing.xs,
        }}
      >
        Tạo tài khoản
      </Text>
      <Text
        style={{
          fontSize: fontSize.sm,
          color: colors.textSecondary,
          marginBottom: spacing.lg,
        }}
      >
        Chào mừng bạn đến với Daigo!
      </Text>

      {(error || localError) && (
        <View
          style={{
            backgroundColor: colors.error,
            padding: spacing.md,
            borderRadius: borderRadius.md,
            marginBottom: spacing.lg,
          }}
        >
          <Text style={{ color: 'white', fontSize: fontSize.sm }}>
            {error || localError}
          </Text>
        </View>
      )}

      <View style={{ marginBottom: spacing.lg }}>
        <TextInput
          label="Họ và tên"
          placeholder="Nhập họ và tên"
          value={fullName}
          onChangeText={(text) => {
            setFullName(text);
            setLocalError('');
          }}
          disabled={isLoading}
          icon={<User size={20} color={colors.textSecondary} />}
          style={{ marginBottom: spacing.lg }}
        />

        <TextInput
          label="Email"
          placeholder="Nhập email"
          value={email}
          onChangeText={(text) => {
            setEmail(text);
            setLocalError('');
          }}
          keyboardType="email-address"
          disabled={isLoading}
          icon={<Mail size={20} color={colors.textSecondary} />}
          style={{ marginBottom: spacing.lg }}
        />

        <TextInput
          label="Số điện thoại"
          placeholder="Nhập số điện thoại"
          value={phone}
          onChangeText={(text) => {
            setPhone(text);
            setLocalError('');
          }}
          keyboardType="phone-pad"
          disabled={isLoading}
          icon={<Phone size={20} color={colors.textSecondary} />}
          style={{ marginBottom: spacing.lg }}
        />

        <TextInput
          label="Mật khẩu"
          placeholder="Nhập mật khẩu"
          value={password}
          onChangeText={(text) => {
            setPassword(text);
            setLocalError('');
          }}
          secureTextEntry={!showPassword}
          disabled={isLoading}
          icon={<Lock size={20} color={colors.textSecondary} />}
          rightIcon={
            <TouchableOpacity onPress={() => setShowPassword((value) => !value)} disabled={isLoading}>
              {showPassword ? (
                <EyeOff size={20} color={colors.textSecondary} />
              ) : (
                <Eye size={20} color={colors.textSecondary} />
              )}
            </TouchableOpacity>
          }
          style={{ marginBottom: spacing.lg }}
        />

        <TextInput
          label="Xác nhận mật khẩu"
          placeholder="Nhập lại mật khẩu"
          value={confirmPassword}
          onChangeText={(text) => {
            setConfirmPassword(text);
            setLocalError('');
          }}
          secureTextEntry={!showConfirmPassword}
          disabled={isLoading}
          icon={<Lock size={20} color={colors.textSecondary} />}
          rightIcon={
            <TouchableOpacity onPress={() => setShowConfirmPassword((value) => !value)} disabled={isLoading}>
              {showConfirmPassword ? (
                <EyeOff size={20} color={colors.textSecondary} />
              ) : (
                <Eye size={20} color={colors.textSecondary} />
              )}
            </TouchableOpacity>
          }
        />
      </View>

      <Button
        label="Đăng ký"
        onPress={handleRegister}
        loading={isLoading}
        disabled={isLoading}
        style={{ marginBottom: spacing.lg }}
      />

      <View
        style={{
          padding: spacing.md,
          borderRadius: borderRadius.md,
          backgroundColor: colors.surfaceAlt,
          marginBottom: spacing.lg,
        }}
      >
        <Text style={{ color: colors.text, fontWeight: '800', marginBottom: spacing.xs }}>
          Bạn muốn lái xe cùng Daigo?
        </Text>
        <Text style={{ color: colors.textSecondary, fontSize: fontSize.sm, lineHeight: 20, marginBottom: spacing.md }}>
          Tài xế xác minh số điện thoại trước, sau đó bổ sung hồ sơ xe và giấy tờ.
        </Text>
        <TouchableOpacity onPress={() => router.push('/(auth)/driver-register')} disabled={isLoading}>
          <Text style={{ color: colors.primary, fontWeight: '800' }}>Đăng ký làm tài xế</Text>
        </TouchableOpacity>
      </View>

      <View
        style={{
          flexDirection: 'row',
          justifyContent: 'center',
          alignItems: 'center',
          gap: spacing.sm,
        }}
      >
        <Text style={{ color: colors.textSecondary, fontSize: fontSize.sm }}>
          Đã có tài khoản?
        </Text>
        <TouchableOpacity onPress={() => router.push('/(auth)/login')} disabled={isLoading}>
          <Text
            style={{
              color: colors.primary,
              fontSize: fontSize.sm,
              fontWeight: '700',
            }}
          >
            Đăng nhập
          </Text>
        </TouchableOpacity>
      </View>

      <View style={{ height: spacing['4xl'] }} />
    </Screen>
  );
}

