import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Image, Text, TouchableOpacity, View } from "react-native";
import { router } from "expo-router";
import { Image as ImageIcon, MessageCircle } from "lucide-react-native";
import { useTheme } from "@/theme";
import { borderRadius, fontSize, spacing } from "@/theme/tokens";
import { AuthRequired } from "@/components/AuthRequired";
import { Button, Skeleton } from "@/components/BaseComponents";
import { Screen } from "@/components/ScreenComponents";
import { SearchFilterBar } from "@/components/SearchFilterBar";
import { useAuthStore } from "@/stores/authStore";
import { useChatStore } from "@/stores/chatStore";
import { apiClient } from "@/services/api";
import { supabase } from "@/services/supabase";

const CHAT_FILTERS = [
  { key: "all", label: "Tất cả" },
  { key: "unread", label: "🔵 Chưa đọc" },
  { key: "read", label: "✅ Đã đọc" },
];

const CHAT_SORTS = [
  { key: "newest", label: "Tin nhắn mới" },
  { key: "oldest", label: "Tin nhắn cũ" },
  { key: "unread", label: "Chưa đọc trước" },
  { key: "name", label: "Theo tên A-Z" },
];

export default function ChatScreen() {
  const { colors } = useTheme();
  const { isAuthenticated, user } = useAuthStore();
  const { conversations, setConversations, setError } = useChatStore();
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [visibleCount, setVisibleCount] = useState(12);
  const [search, setSearch] = useState("");
  const [activeFilter, setActiveFilter] = useState("all");
  const [activeSort, setActiveSort] = useState("newest");
  const channelInstanceId = useRef(Math.random().toString(36).slice(2)).current;

  const refreshConversations = useCallback(async () => {
    if (!user) return;
    try {
      setRefreshing(true);
      setConversations(await apiClient.getConversations(user.id));
    } catch (error: any) {
      setError(error.message);
    } finally {
      setRefreshing(false);
    }
  }, [setConversations, setError, user]);

  const initialLoad = useCallback(async () => {
    if (!user) return;
    try {
      setLoading(true);
      setConversations(await apiClient.getConversations(user.id));
    } catch (error: any) {
      setError(error.message);
    } finally {
      setLoading(false);
    }
  }, [setConversations, setError, user]);

  useEffect(() => {
    if (!user) return;
    let active = true;

    initialLoad();

    const refreshFromRealtime = () => {
      if (!active) return;
      apiClient
        .getConversations(user.id)
        .then((items) => {
          if (active) setConversations(items);
        })
        .catch((error) => {
          if (active) setError(error.message);
        });
    };

    const channel = supabase
      .channel(`chat-list-${user.id}-${channelInstanceId}`)
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "conversations" },
        refreshFromRealtime,
      )
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "messages" },
        refreshFromRealtime,
      )
      .subscribe();

    return () => {
      active = false;
      supabase.removeChannel(channel);
    };
  }, [initialLoad, setConversations, setError, user, channelInstanceId]);

  const filteredConversations = useMemo(() => {
    let result = [...conversations];

    // Search
    if (search.trim()) {
      const q = search.toLowerCase();
      result = result.filter(
        (c) =>
          c.participantName?.toLowerCase().includes(q) ||
          c.lastMessage?.toLowerCase().includes(q),
      );
    }

    // Filter
    if (activeFilter === "unread")
      result = result.filter((c) => c.unreadCount > 0);
    if (activeFilter === "read")
      result = result.filter((c) => !c.unreadCount || c.unreadCount === 0);

    // Sort
    if (activeSort === "unread")
      result.sort((a, b) => (b.unreadCount ?? 0) - (a.unreadCount ?? 0));
    if (activeSort === "name")
      result.sort((a, b) =>
        (a.participantName ?? "").localeCompare(b.participantName ?? ""),
      );
    if (activeSort === "oldest") result = [...result].reverse();

    return result;
  }, [conversations, search, activeFilter, activeSort]);

  if (!isAuthenticated) {
    return (
      <AuthRequired description="Bạn cần đăng nhập để trò chuyện với tài xế." />
    );
  }

  if (!user?.phoneVerified) {
    return (
      <AuthRequired
        title="Xác minh số điện thoại"
        description="Bạn cần xác minh SĐT bằng OTP trước khi chat hoặc gọi tài xế."
        actionLabel="Xác minh SĐT"
        onActionPress={() => router.push({ pathname: "/(auth)/phone-otp" as any, params: { redirectTo: "/(customer)/chat" } })}
      />
    );
  }

  return (
    <Screen scroll refreshing={refreshing} onRefresh={refreshConversations}>
      <View style={{ paddingHorizontal: spacing.lg, paddingTop: spacing.md }}>
        <SearchFilterBar
          searchValue={search}
          onSearchChange={setSearch}
          placeholder="Tìm tài xế hoặc tin nhắn..."
          filters={CHAT_FILTERS}
          activeFilter={activeFilter}
          onFilterChange={setActiveFilter}
          sortOptions={CHAT_SORTS}
          activeSort={activeSort}
          onSortChange={(key) => setActiveSort(key || "newest")}
          resultCount={loading ? undefined : filteredConversations.length}
          resultLabel="cuộc trò chuyện"
        />
      </View>

      {/* Skeleton loading lần đầu */}
      {loading && (
        <View style={{ paddingHorizontal: spacing.lg, paddingTop: spacing.sm }}>
          {[1, 2, 3, 4, 5].map((i) => (
            <View
              key={i}
              style={{
                flexDirection: "row",
                alignItems: "center",
                gap: spacing.md,
                paddingVertical: spacing.md,
                borderBottomWidth: 1,
                borderBottomColor: colors.border,
              }}
            >
              <Skeleton width={58} height={58} borderRadius={29} />
              <View style={{ flex: 1, gap: spacing.sm }}>
                <Skeleton width="60%" height={16} />
                <Skeleton width="85%" height={12} />
              </View>
              <View style={{ alignItems: "flex-end", gap: spacing.sm }}>
                <Skeleton width={36} height={10} />
              </View>
            </View>
          ))}
        </View>
      )}

      {!loading && filteredConversations.slice(0, visibleCount).map((conversation) => (
        <TouchableOpacity
          key={conversation.id}
          activeOpacity={0.84}
          onPress={() =>
            router.push({
              pathname: "/(customer)/chat-detail" as any,
              params: { id: conversation.id },
            })
          }
        >
          <View
            style={{
              backgroundColor: colors.surface,
              borderTopWidth: 1,
              borderBottomWidth: 1,
              borderColor: colors.border,
              paddingHorizontal: spacing.lg,
              paddingVertical: spacing.md,
            }}
          >
            <View
              style={{
                flexDirection: "row",
                gap: spacing.md,
                alignItems: "center",
              }}
            >
              <View>
                <Image
                  source={{ uri: conversation.participantAvatar }}
                  style={{
                    width: 58,
                    height: 58,
                    borderRadius: 29,
                    backgroundColor: colors.surfaceAlt,
                  }}
                />
              </View>
              <View style={{ flex: 1 }}>
                <View style={{ flexDirection: "row", alignItems: "center", gap: spacing.xs }}>
                  <Text
                    style={{
                      color: colors.text,
                      fontSize: 16,
                      fontWeight: "900",
                      flex: 1,
                    }}
                    numberOfLines={1}
                  >
                    {conversation.participantName}
                  </Text>
                  <MessageCircle size={14} color={colors.primary} />
                </View>
                <Text
                  numberOfLines={1}
                  style={{
                    color: conversation.unreadCount > 0 ? colors.text : colors.textSecondary,
                    fontSize: fontSize.sm,
                    fontWeight: conversation.unreadCount > 0 ? "800" : "500",
                    marginTop: spacing.xs,
                  }}
                >
                  {conversation.lastMessage === "Đã gửi một ảnh" ? "Ảnh trong cuộc trò chuyện" : conversation.lastMessage}
                </Text>
                {conversation.lastMessage === "Đã gửi một ảnh" && (
                  <View style={{ flexDirection: "row", alignItems: "center", gap: spacing.xs, marginTop: spacing.xs }}>
                    <ImageIcon size={13} color={colors.primary} />
                    <Text style={{ color: colors.textTertiary, fontSize: fontSize.xs }}>Nhấn để xem ảnh</Text>
                  </View>
                )}
                {(conversation.threadIds?.length ?? 0) > 1 && (
                  <Text
                    style={{
                      color: colors.textTertiary,
                      fontSize: fontSize.xs,
                      marginTop: spacing.xs,
                    }}
                  >
                    {conversation.threadIds?.length} chuyến cùng tài xế
                  </Text>
                )}
              </View>
              <View style={{ alignItems: "flex-end", gap: spacing.sm }}>
                <Text
                  style={{ color: colors.textTertiary, fontSize: fontSize.xs }}
                >
                  {conversation.lastMessageTime}
                </Text>
                {conversation.unreadCount > 0 && (
                  <View
                    style={{
                      minWidth: 22,
                      height: 22,
                      borderRadius: borderRadius.full,
                      backgroundColor: colors.primary,
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <Text
                      style={{
                        color: "white",
                        fontSize: fontSize.xs,
                        fontWeight: "700",
                      }}
                    >
                      {conversation.unreadCount}
                    </Text>
                  </View>
                )}
              </View>
            </View>
          </View>
        </TouchableOpacity>
      ))}
      {!loading && filteredConversations.length === 0 && (
        <Text
          style={{
            color: colors.textSecondary,
            textAlign: "center",
            marginTop: spacing.xl,
          }}
        >
          {search || activeFilter !== "all"
            ? "Không tìm thấy cuộc trò chuyện phù hợp."
            : "Chưa có cuộc trò chuyện. Conversation sẽ được tạo sau khi bạn đặt xe."}
        </Text>
      )}
      {!loading && filteredConversations.length > visibleCount && (
        <Button
          label="Tải thêm tin nhắn"
          onPress={() => setVisibleCount((current) => current + 12)}
          variant="outline"
        />
      )}
    </Screen>
  );
}

