import React, { useEffect, useMemo, useState } from 'react';
import { Text, TouchableOpacity, View } from 'react-native';
import { router } from 'expo-router';
import { Bell, CheckCircle2 } from 'lucide-react-native';
import { useTheme } from '@/theme';
import { fontSize, spacing } from '@/theme/tokens';
import { Button, Skeleton } from '@/components/BaseComponents';
import { EmptyState, Screen } from '@/components/ScreenComponents';
import { SearchFilterBar } from '@/components/SearchFilterBar';
import { AuthRequired } from '@/components/AuthRequired';
import { useAuthStore } from '@/stores/authStore';
import { useNotifications } from '@/hooks/useNotifications';

const NOTIF_FILTERS = [
  { key: 'all', label: 'Tất cả' },
  { key: 'unread', label: '🔵 Chưa đọc' },
  { key: 'read', label: '✅ Đã đọc' },
];

const NOTIF_SORTS = [
  { key: 'newest', label: 'Mới nhất' },
  { key: 'oldest', label: 'Cũ nhất' },
];

export default function NotificationsScreen() {
  const { colors } = useTheme();
  const { isAuthenticated, user } = useAuthStore();
  const { notifications, fetchNotifications, markAsRead, isLoading } = useNotifications(user?.id);
  const [visibleCount, setVisibleCount] = useState(20);
  const [search, setSearch] = useState('');
  const [activeFilter, setActiveFilter] = useState('all');
  const [activeSort, setActiveSort] = useState('newest');

  useEffect(() => {
    fetchNotifications();
  }, [fetchNotifications]);

  const filteredNotifications = useMemo(() => {
    let result = [...notifications];
    if (search.trim()) {
      const q = search.toLowerCase();
      result = result.filter(
        (n) =>
          n.title?.toLowerCase().includes(q) ||
          n.content?.toLowerCase().includes(q)
      );
    }
    if (activeFilter === 'unread') result = result.filter((n) => !n.read);
    if (activeFilter === 'read') result = result.filter((n) => n.read);
    if (activeSort === 'oldest') result = [...result].reverse();
    return result;
  }, [notifications, search, activeFilter, activeSort]);

  if (!isAuthenticated) {
    return <AuthRequired description="Bạn cần đăng nhập để xem thông báo cá nhân." />;
  }

  return (
    <Screen scroll refreshing={isLoading} onRefresh={fetchNotifications}>
      {/* Search bar — với padding ngang */}
      <View style={{ paddingHorizontal: spacing.lg, paddingTop: spacing.md }}>
        <SearchFilterBar
          searchValue={search}
          onSearchChange={setSearch}
          placeholder="Tìm tiêu đề, nội dung thông báo..."
          filters={NOTIF_FILTERS}
          activeFilter={activeFilter}
          onFilterChange={setActiveFilter}
          sortOptions={NOTIF_SORTS}
          activeSort={activeSort}
          onSortChange={(key) => setActiveSort(key || 'newest')}
          resultCount={isLoading ? undefined : filteredNotifications.length}
          resultLabel="thông báo"
        />
      </View>

      {/* Loading skeletons */}
      {isLoading ? (
        <View>
          {[1, 2, 3, 4].map((i) => (
            <View
              key={i}
              style={{
                flexDirection: 'row',
                alignItems: 'center',
                gap: spacing.md,
                paddingHorizontal: spacing.lg,
                paddingVertical: spacing.md,
                borderBottomWidth: 1,
                borderBottomColor: colors.border,
              }}
            >
              <Skeleton width={42} height={42} borderRadius={21} />
              <View style={{ flex: 1, gap: spacing.xs }}>
                <Skeleton width="70%" height={14} />
                <Skeleton width="90%" height={12} />
                <Skeleton width="40%" height={10} />
              </View>
            </View>
          ))}
        </View>
      ) : (
        /* Flat list — sát 2 bên, ngăn cách bằng border */
        <View>
          {filteredNotifications.slice(0, visibleCount).map((notification) => (
            <TouchableOpacity
              key={notification.id}
              activeOpacity={0.7}
              onPress={() => {
                if (!notification.read) markAsRead(notification.id);
                router.push({
                  pathname: '/(customer)/notification-detail' as any,
                  params: { id: notification.id },
                });
              }}
              style={{
                flexDirection: 'row',
                alignItems: 'flex-start',
                gap: spacing.md,
                paddingHorizontal: spacing.lg,
                paddingVertical: spacing.md + 2,
                backgroundColor: notification.read
                  ? colors.background
                  : colors.primary + '08',
                borderBottomWidth: 1,
                borderBottomColor: colors.border,
              }}
            >
              {/* Icon */}
              <View
                style={{
                  width: 42,
                  height: 42,
                  borderRadius: 21,
                  backgroundColor: notification.read
                    ? colors.surfaceAlt
                    : colors.primary + '20',
                  alignItems: 'center',
                  justifyContent: 'center',
                  flexShrink: 0,
                  borderWidth: notification.read ? 0 : 1.5,
                  borderColor: notification.read ? 'transparent' : colors.primary + '40',
                }}
              >
                {notification.read
                  ? <CheckCircle2 size={20} color={colors.textSecondary} />
                  : <Bell size={20} color={colors.primary} />
                }
              </View>

              {/* Content */}
              <View style={{ flex: 1 }}>
                <View style={{ flexDirection: 'row', alignItems: 'flex-start', justifyContent: 'space-between', gap: spacing.sm }}>
                  <Text
                    style={{
                      color: colors.text,
                      fontSize: fontSize.base,
                      fontWeight: notification.read ? '600' : '700',
                      flex: 1,
                      lineHeight: 22,
                    }}
                    numberOfLines={2}
                  >
                    {notification.title}
                  </Text>
                  {!notification.read && (
                    <View
                      style={{
                        width: 8,
                        height: 8,
                        borderRadius: 4,
                        backgroundColor: colors.primary,
                        marginTop: 7,
                        flexShrink: 0,
                      }}
                    />
                  )}
                </View>
                <Text
                  numberOfLines={2}
                  style={{
                    color: colors.textSecondary,
                    fontSize: fontSize.sm,
                    marginTop: 3,
                    lineHeight: 20,
                  }}
                >
                  {notification.content}
                </Text>
                <Text
                  style={{
                    color: colors.textTertiary,
                    fontSize: fontSize.xs,
                    marginTop: spacing.xs,
                  }}
                >
                  {notification.time}
                </Text>
              </View>
            </TouchableOpacity>
          ))}
        </View>
      )}

      {/* Empty state */}
      {!isLoading && filteredNotifications.length === 0 && (
        search || activeFilter !== 'all' ? (
          <Text style={{ color: colors.textSecondary, textAlign: 'center', marginTop: spacing.xl, paddingHorizontal: spacing.lg }}>
            Không tìm thấy thông báo phù hợp.
          </Text>
        ) : (
          <EmptyState
            icon={<Bell size={48} color={colors.primary} />}
            title="Chưa có thông báo"
            description="Thông báo đặt xe và hệ thống sẽ hiển thị tại đây."
          />
        )
      )}

      {/* Load more */}
      {!isLoading && filteredNotifications.length > visibleCount && (
        <View style={{ paddingHorizontal: spacing.lg, marginTop: spacing.md }}>
          <Button
            label="Tải thêm thông báo"
            onPress={() => setVisibleCount((current) => current + 20)}
            variant="outline"
          />
        </View>
      )}
    </Screen>
  );
}

