        </View>
        <TouchableOpacity
          onPress={onCallPress}
          style={{
            width: 40,
            height: 40,
            borderRadius: 20,
            alignItems: 'center',
            justifyContent: 'center',
            backgroundColor: colors.primary,
          }}
        >
          <Phone size={18} color="white" />
