    >
      <Text style={{ color: colors.text, fontSize: 18, fontWeight: '900', marginBottom: spacing.md }}>
        Quét VietQR để chuyển khoản
      </Text>
      {!!payment.qrUrl && (
        <View style={{ alignItems: 'center', marginBottom: spacing.lg }}>
          <Image
            source={{ uri: payment.qrUrl }}
            resizeMode="contain"
            style={{
              width: '100%',
              height: 280,
              borderRadius: borderRadius.lg,
              backgroundColor: 'white',
            }}
          />
        </View>
      )}
      <Text style={{ color: colors.primary, fontSize: 26, fontWeight: '900', marginBottom: spacing.md }}>
        {payment.amount.toLocaleString('vi-VN')} VND
      </Text>
      <View style={{ gap: spacing.sm }}>
        {rows.map((row) => (
          <View
            key={row.label}
            style={{
              flexDirection: 'row',
              alignItems: 'center',
              gap: spacing.sm,
              padding: spacing.md,
              borderRadius: borderRadius.lg,
              backgroundColor: colors.surfaceAlt,
            }}
          >
            <View style={{ flex: 1 }}>
              <Text style={{ color: colors.textSecondary, fontSize: fontSize.xs }}>{row.label}</Text>
              <Text style={{ color: colors.text, fontWeight: '800', marginTop: spacing.xs }}>{row.value}</Text>
            </View>
            {!!row.copyLabel && (
              <TouchableOpacity
                onPress={() => copy(row.copyLabel!, row.value)}
                style={{
                  width: 38,
                  height: 38,
                  borderRadius: borderRadius.full,
                  alignItems: 'center',
                  justifyContent: 'center',
                  backgroundColor: colors.surface,
                }}
              >
                <Copy size={18} color={colors.primary} />
              </TouchableOpacity>
            )}
          </View>
        ))}
      </View>
      {!!payment.qrUrl && (
        <TouchableOpacity
          onPress={shareQr}
          style={{
            flexDirection: 'row',
            alignItems: 'center',
            justifyContent: 'center',
            gap: spacing.sm,
            marginTop: spacing.md,
            padding: spacing.md,
            borderRadius: borderRadius.lg,
            borderWidth: 1,
            borderColor: colors.border,
          }}
        >
          <Share2 size={18} color={colors.primary} />
          <Text style={{ color: colors.primary, fontWeight: '800' }}>Chia sẻ QR</Text>
        </TouchableOpacity>
      )}
    </View>
  );
}

