import { useNotificationStore } from '@/stores/notificationStore';
import { useCallback, useEffect, useRef } from 'react';
import { apiClient } from '@/services/api';
import { supabase } from '@/services/supabase';

export const useNotifications = (userId?: string) => {
  const notifications = useNotificationStore((state) => state.notifications);
  const unreadCount = useNotificationStore((state) => state.unreadCount);
  const isLoading = useNotificationStore((state) => state.isLoading);
  const error = useNotificationStore((state) => state.error);
  const setNotifications = useNotificationStore((state) => state.setNotifications);
  const markNotificationAsRead = useNotificationStore((state) => state.markAsRead);
  const clearNotifications = useNotificationStore((state) => state.clearNotifications);
  const setLoading = useNotificationStore((state) => state.setLoading);
  const setError = useNotificationStore((state) => state.setError);
  const channelRef = useRef<ReturnType<typeof supabase.channel> | null>(null);
  const instanceIdRef = useRef(Math.random().toString(36).slice(2));
  const debugNotifications = process.env.EXPO_PUBLIC_ENV !== 'production';

  const fetchNotifications = useCallback(async () => {
    if (!userId) {
      clearNotifications();
      setLoading(false);
      return;
    }
    try {
      setLoading(true);
      const notifications = await apiClient.getNotifications(userId);
      if (debugNotifications) {
        console.warn('[DAIGO_NOTIFICATIONS_FETCH]', {
          userId,
          count: notifications.length,
        });
      }
      setNotifications(notifications);
      setLoading(false);
    } catch (err: any) {
      if (debugNotifications) {
        console.warn('[DAIGO_NOTIFICATIONS_ERROR]', {
          userId,
          message: err?.message,
          code: err?.code,
          details: err?.details,
        });
      }
      setError(err.message);
      setLoading(false);
    }
  }, [clearNotifications, debugNotifications, setError, setLoading, setNotifications, userId]);

  const markAsRead = useCallback(async (notificationId: string) => {
    try {
      await apiClient.markNotificationAsRead(notificationId);
      markNotificationAsRead(notificationId);
    } catch (err: any) {
      setError(err.message);
    }
  }, [markNotificationAsRead, setError]);

  useEffect(() => {
    if (channelRef.current) {
      supabase.removeChannel(channelRef.current);
      channelRef.current = null;
    }

    if (!userId) {
      clearNotifications();
      setLoading(false);
      return;
    }

    let active = true;
    const channel = supabase
      .channel(`notifications-${userId}-${instanceIdRef.current}`)
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'notifications', filter: `user_id=eq.${userId}` },
        () => {
          if (active) fetchNotifications();
        }
      )
      .subscribe((status, error) => {
        if (debugNotifications) {
          console.warn('[DAIGO_NOTIFICATIONS_SUBSCRIPTION]', {
            userId,
            status,
            error: error?.message,
          });
        }
      });
    channelRef.current = channel;

    return () => {
      active = false;
      supabase.removeChannel(channel);
      if (channelRef.current === channel) channelRef.current = null;
    };
  }, [clearNotifications, debugNotifications, fetchNotifications, setLoading, userId]);

  return {
    notifications,
    unreadCount,
    isLoading,
    error,
    fetchNotifications,
    markAsRead,
  };
};

import { useCallback, useEffect, useState } from 'react';
import { Booking, Payment, PaymentMethod, User } from '@/types';
import { paymentService } from '@/services/paymentService';

export function usePayment(bookingId?: string) {
  const [payment, setPayment] = useState<Payment | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadPayment = useCallback(async () => {
    if (!bookingId) return;
    try {
      setLoading(true);
      setError(null);
      setPayment(await paymentService.getPaymentByBooking(bookingId));
    } catch (paymentError: any) {
      setError(paymentError.message || 'Không thể tải thanh toán.');
    } finally {
      setLoading(false);
    }
  }, [bookingId]);

  const createOrGetPayment = useCallback(async (booking: Booking, user: User, method?: PaymentMethod) => {
    setLoading(true);
    setError(null);
    try {
      const nextPayment = await paymentService.createOrGetPayment(booking, user, method);
      setPayment(nextPayment);
      return nextPayment;
    } catch (paymentError: any) {
      setError(paymentError.message || 'Không thể tạo thanh toán.');
      throw paymentError;
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadPayment();
  }, [loadPayment]);

  useEffect(() => {
    if (!bookingId) return undefined;
    return paymentService.subscribePayment(bookingId, setPayment);
  }, [bookingId]);

  return {
    payment,
    setPayment,
    loading,
    error,
    reload: loadPayment,
    createOrGetPayment,
  };
}

