  async getConversations(userId: string): Promise<ChatConversation[]> {
    const { data, error } = await supabase
      .from('conversations')
      .select('*, customer:profiles!conversations_customer_id_fkey(*), driver:profiles!conversations_driver_id_fkey(*), messages(*, profiles!messages_sender_id_fkey(full_name, role), reply:messages!reply_to_message_id(text, sender_id, profiles!messages_sender_id_fkey(full_name)))')
      .or(`customer_id.eq.${userId},driver_id.eq.${userId}`)
      .order('updated_at', { ascending: false });
    if (error) throw error;

    const conversations = (data ?? []).map((row: any) => {
      const participant = row.customer_id === userId ? row.driver : row.customer;
      const messages = [...(row.messages ?? [])].sort(
        (a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
      );
      const mappedMessages: Message[] = messages.map((message: any) => ({
        id: message.id,
        sender: message.sender_id === userId ? 'user' as const : 'driver' as const,
        senderName: message.profiles?.full_name ?? 'Người dùng',
        text: message.text,
        mediaUrl: message.media_url ?? undefined,
        mediaType: message.media_type ?? undefined,
        replyToMessageId: message.reply_to_message_id ?? undefined,
        replyToText: message.reply?.text ?? undefined,
        replyToSenderName: message.reply?.profiles?.full_name ?? undefined,
        timestamp: message.created_at,
        read: message.read,
      }));
      const lastMessage = mappedMessages[mappedMessages.length - 1];

      return {
        id: row.id,
        bookingId: row.booking_id ?? undefined,
        threadIds: [row.id],
        participantId: participant?.id ?? '',
        participantName: participant?.full_name ?? 'Tài xế sẽ xác nhận',
        participantPhone: participant?.phone ?? undefined,
        participantAvatar: participant?.avatar_url ?? undefined,
        lastMessage: lastMessage?.text ?? 'Chưa có tin nhắn',
        lastMessageTime: lastMessage?.timestamp ? new Date(lastMessage.timestamp).toLocaleString('vi-VN') : '',
        unreadCount: messages.filter((message: any) => !message.read && message.sender_id !== userId).length,
        messages: mappedMessages,
        updatedAt: row.updated_at,
      };
    });

    const grouped = new Map<string, ChatConversation & { updatedAt?: string }>();
    conversations.forEach((conversation) => {
      const key = conversation.participantId || conversation.id;
      const existing = grouped.get(key);
      if (!existing) {
        grouped.set(key, conversation);
        return;
      }

      const mergedMessages = [...existing.messages, ...conversation.messages].sort(
        (a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );
      const lastMessage = mergedMessages[mergedMessages.length - 1];
      const keepCurrentId =
        new Date(conversation.updatedAt ?? 0).getTime() >= new Date(existing.updatedAt ?? 0).getTime();

      grouped.set(key, {
        ...existing,
        id: keepCurrentId ? conversation.id : existing.id,
        bookingId: keepCurrentId ? conversation.bookingId : existing.bookingId,
        threadIds: Array.from(new Set([...(existing.threadIds ?? [existing.id]), ...(conversation.threadIds ?? [conversation.id])])),
        unreadCount: existing.unreadCount + conversation.unreadCount,
        messages: mergedMessages,
        lastMessage: lastMessage?.text ?? existing.lastMessage,
        lastMessageTime: lastMessage?.timestamp ? new Date(lastMessage.timestamp).toLocaleString('vi-VN') : existing.lastMessageTime,
        updatedAt: keepCurrentId ? conversation.updatedAt : existing.updatedAt,
      });
    });

    return Array.from(grouped.values())
      .sort((a, b) => new Date(b.updatedAt ?? 0).getTime() - new Date(a.updatedAt ?? 0).getTime())
      .map(({ updatedAt: _updatedAt, ...conversation }) => conversation);
  }

  async sendMessage(
    conversationId: string,
    message: string,
    senderId: string,
    media?: { url: string; type: 'image' | 'video' },
    replyToMessageId?: string
  ): Promise<Message> {
    const { data, error } = await supabase
      .from('messages')
      .insert({
        conversation_id: conversationId,
        sender_id: senderId,
        text: message,
        media_url: media?.url,
        media_type: media?.type,
        reply_to_message_id: replyToMessageId,
      })
      .select('*, profiles!messages_sender_id_fkey(full_name, role), reply:messages!reply_to_message_id(text, sender_id, profiles!messages_sender_id_fkey(full_name))')
      .single();
    if (error) throw error;
    return {
      id: data.id,
      sender: 'user',
      senderName: data.profiles?.full_name ?? 'Bạn',
      text: data.text,
      mediaUrl: data.media_url ?? undefined,
      mediaType: data.media_type ?? undefined,
      replyToMessageId: data.reply_to_message_id ?? undefined,
      replyToText: data.reply?.text ?? undefined,
      replyToSenderName: data.reply?.profiles?.full_name ?? undefined,
      timestamp: data.created_at,
      read: data.read,
    };
  }

  async deleteMessage(messageId: string, senderId: string): Promise<void> {
    const { error } = await supabase
      .from('messages')
      .delete()
      .eq('id', messageId)
      .eq('sender_id', senderId);
    if (error) throw error;
  }

  async markConversationMessagesAsRead(conversationId: string, userId: string): Promise<void> {
    const { error } = await supabase
      .from('messages')
      .update({ read: true })
      .eq('conversation_id', conversationId)
      .neq('sender_id', userId);
    if (error) throw error;
  }

  async markConversationThreadMessagesAsRead(conversationId: string, userId: string): Promise<void> {
    const { data: conversation, error } = await supabase
      .from('conversations')
      .select('customer_id, driver_id')
      .eq('id', conversationId)
      .single();
    if (error) throw error;

    const participantId =
      conversation.customer_id === userId ? conversation.driver_id : conversation.customer_id;

    if (!participantId) {
      await this.markConversationMessagesAsRead(conversationId, userId);
      return;
    }

    const { data: conversations, error: listError } = await supabase
      .from('conversations')
      .select('id')
      .or(
        `and(customer_id.eq.${userId},driver_id.eq.${participantId}),and(customer_id.eq.${participantId},driver_id.eq.${userId})`
      );
    if (listError) throw listError;

    const ids = (conversations ?? []).map((item: any) => item.id);
    if (ids.length === 0) return;

    const { error: updateError } = await supabase
      .from('messages')
      .update({ read: true })
      .in('conversation_id', ids)
      .neq('sender_id', userId);
    if (updateError) throw updateError;
  }
}

export const apiClient = new ApiClient();

import { Platform } from 'react-native';
import Constants from 'expo-constants';
import { apiClient } from '@/services/api';
import { showInfo, showWarning } from '@/utils/toast';

let notificationHandlerReady = false;

async function getNotificationsModule() {
  const Notifications = await import('expo-notifications');

  if (!notificationHandlerReady) {
    Notifications.setNotificationHandler({
      handleNotification: async () => ({
        shouldPlaySound: true,
        shouldSetBadge: true,
        shouldShowBanner: true,
        shouldShowList: true,
      }),
    });
    notificationHandlerReady = true;
  }

  return Notifications;
}

export async function registerPushNotifications(userId: string) {
  if (Constants.appOwnership === 'expo') {
    return null;
  }

  const Device = await import('expo-device');
  const Notifications = await getNotificationsModule();

  if (!Device.isDevice) {
    showInfo('Push notification', 'Expo Push chỉ hoạt động đầy đủ trên thiết bị thật hoặc APK/dev build.');
    return null;
  }

  if (Platform.OS === 'android') {
    await Notifications.setNotificationChannelAsync('default', {
      name: 'Thông báo Daigo',
      importance: Notifications.AndroidImportance.MAX,
      vibrationPattern: [0, 250, 250, 250],
      lightColor: '#1d4ed8',
    });
  }

  const current = await Notifications.getPermissionsAsync();
  let finalStatus = current.status;
  if (finalStatus !== 'granted') {
    const requested = await Notifications.requestPermissionsAsync();
    finalStatus = requested.status;
  }

  if (finalStatus !== 'granted') {
    showWarning('Chưa bật thông báo', 'Bạn có thể bật quyền thông báo trong cài đặt thiết bị để nhận booking/chat realtime.');
    return null;
  }

  const projectId =
    Constants.expoConfig?.extra?.eas?.projectId ??
    Constants.easConfig?.projectId;
  if (!projectId) {
    showWarning('Thiếu EAS projectId', 'Không thể lấy Expo Push Token vì app chưa có projectId.');
    return null;
  }

  const token = (await Notifications.getExpoPushTokenAsync({ projectId })).data;
  await apiClient.upsertPushToken(userId, token, Platform.OS);
  return token;
}

import 'react-native-url-polyfill/auto';
import * as SecureStore from 'expo-secure-store';
import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.EXPO_PUBLIC_SUPABASE_URL;
const supabaseKey = process.env.EXPO_PUBLIC_SUPABASE_PUBLISHABLE_KEY;

if (!supabaseUrl || !supabaseKey) {
  throw new Error('Missing Supabase environment variables');
}

const CHUNK_SIZE = 1900;
const sanitizeKey = (key: string) => key.replace(/[^A-Za-z0-9._-]/g, '_');
const metaKey = (key: string) => `${sanitizeKey(key)}_meta`;
const chunkKey = (key: string, index: number) => `${sanitizeKey(key)}_${index}`;

const secureStorage = {
  async getItem(key: string) {
    const meta = await SecureStore.getItemAsync(metaKey(key));
    const chunkCount = meta ? Number(meta) : 0;

    if (!chunkCount) {
      return SecureStore.getItemAsync(sanitizeKey(key));
    }

    const chunks = await Promise.all(
      Array.from({ length: chunkCount }, (_, index) => SecureStore.getItemAsync(chunkKey(key, index)))
    );

    return chunks.filter(Boolean).join('');
  },

  async setItem(key: string, value: string) {
    const safeKey = sanitizeKey(key);
    const oldMeta = await SecureStore.getItemAsync(metaKey(key));
    const oldChunkCount = oldMeta ? Number(oldMeta) : 0;

    await SecureStore.deleteItemAsync(safeKey);
    for (let index = 0; index < oldChunkCount; index += 1) {
      await SecureStore.deleteItemAsync(chunkKey(key, index));
    }

    if (value.length <= CHUNK_SIZE) {
      await SecureStore.deleteItemAsync(metaKey(key));
      await SecureStore.setItemAsync(safeKey, value);
      return;
    }

    const chunks = value.match(new RegExp(`.{1,${CHUNK_SIZE}}`, 'g')) ?? [];
    await SecureStore.setItemAsync(metaKey(key), String(chunks.length));
    await Promise.all(
      chunks.map((chunk, index) => SecureStore.setItemAsync(chunkKey(key, index), chunk))
    );
  },

  async removeItem(key: string) {
    const safeKey = sanitizeKey(key);
    const meta = await SecureStore.getItemAsync(metaKey(key));
    const chunkCount = meta ? Number(meta) : 0;

    await SecureStore.deleteItemAsync(safeKey);
    await SecureStore.deleteItemAsync(metaKey(key));
    await Promise.all(
      Array.from({ length: chunkCount }, (_, index) => SecureStore.deleteItemAsync(chunkKey(key, index)))
    );
  },
};

export const supabase = createClient(supabaseUrl, supabaseKey, {
  auth: {
    storage: secureStorage,
    autoRefreshToken: true,
    persistSession: true,
    detectSessionInUrl: false,
  },
  realtime: {
    params: {
      eventsPerSecond: 10,
    },
  },
});

import { create } from 'zustand';
import { AuthCredentials, DriverOnboardingData, RegisterData, User } from '@/types';
import { apiClient } from '@/services/api';
import { toVietnameseAuthError } from '@/utils/authValidation';

interface AuthStore {
  user: User | null;
  token: string | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  /** True once the initial session-restore attempt has completed (success or not). */
  isSessionRestored: boolean;
  error: string | null;
  login: (credentials: AuthCredentials) => Promise<{ user: User; token: string }>;
  register: (data: RegisterData) => Promise<{ user: User; token: string }>;
  loginWithGoogle: (redirectTo: string) => Promise<{ user: User; token: string }>;
  sendPhoneOtp: (phone: string) => Promise<void>;
  verifyPhoneOtp: (phone: string, token: string, profileData?: Partial<User>) => Promise<{ user: User; token: string }>;
  startDriverOnboarding: (data: DriverOnboardingData) => Promise<User>;
  resendSignupOtp: (email: string) => Promise<void>;
  verifySignupOtp: (email: string, token: string) => Promise<{ user: User; token: string }>;
  resetPassword: (email: string, redirectTo?: string) => Promise<void>;
  updatePassword: (password: string) => Promise<void>;
  logout: () => Promise<void>;
  setUser: (user: User | null) => void;
  setToken: (token: string | null) => void;
  setError: (error: string | null) => void;
  setLoading: (loading: boolean) => void;
  restoreSession: (user: User, token: string) => void;
}

export const useAuthStore = create<AuthStore>((set) => ({
  user: null,
  token: null,
  isLoading: false,
  isAuthenticated: false,
  isSessionRestored: false,
  error: null,

  login: async (credentials) => {
    set({ isLoading: true, error: null });
    try {
      const response = await apiClient.login(credentials);
      set({
        user: response.user,
        token: response.token,
        isAuthenticated: true,
        isLoading: false,
      });
      return response;
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Đăng nhập không thành công', isLoading: false });
      throw error;
    }
  },

  register: async (data) => {
    set({ isLoading: true, error: null });
    try {
      const response = await apiClient.register(data);
      set({
        user: response.user,
        token: response.token,
        isAuthenticated: !!response.token,
        isLoading: false,
      });
      return response;
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Đăng ký không thành công', isLoading: false });
      throw error;
    }
  },

  loginWithGoogle: async (redirectTo) => {
    set({ isLoading: true, error: null });
    try {
      const response = await apiClient.loginWithGoogle(redirectTo);
      set({
        user: response.user,
        token: response.token,
        isAuthenticated: true,
        isLoading: false,
      });
      return response;
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Đăng nhập Google không thành công', isLoading: false });
      throw error;
    }
  },

  sendPhoneOtp: async (phone) => {
    set({ isLoading: true, error: null });
    try {
      await apiClient.sendPhoneOtp(phone);
      set({ isLoading: false });
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Không thể gửi OTP điện thoại', isLoading: false });
      throw error;
    }
  },

  verifyPhoneOtp: async (phone, token, profileData) => {
    set({ isLoading: true, error: null });
    try {
      const response = await apiClient.verifyPhoneOtp(phone, token, profileData);
      set({
        user: response.user,
        token: response.token,
        isAuthenticated: true,
        isLoading: false,
      });
      return response;
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'OTP điện thoại không hợp lệ', isLoading: false });
      throw error;
    }
  },

  startDriverOnboarding: async (data) => {
    set({ isLoading: true, error: null });
    try {
      const user = await apiClient.startDriverOnboarding(data);
      set({
        user,
        isAuthenticated: true,
        isLoading: false,
      });
      return user;
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Không thể cập nhật hồ sơ tài xế', isLoading: false });
      throw error;
    }
  },

  resendSignupOtp: async (email) => {
    set({ isLoading: true, error: null });
    try {
      await apiClient.resendSignupOtp(email);
      set({ isLoading: false });
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Không thể gửi OTP', isLoading: false });
      throw error;
    }
  },

  verifySignupOtp: async (email, token) => {
    set({ isLoading: true, error: null });
    try {
      const response = await apiClient.verifySignupOtp(email, token);
      set({
        user: response.user,
        token: response.token,
        isAuthenticated: true,
        isLoading: false,
      });
      return response;
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'OTP không hợp lệ', isLoading: false });
      throw error;
    }
  },

  resetPassword: async (email, redirectTo) => {
    set({ isLoading: true, error: null });
    try {
      await apiClient.resetPassword(email, redirectTo);
      set({ isLoading: false });
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Không thể gửi email đặt lại mật khẩu', isLoading: false });
      throw error;
    }
  },

  updatePassword: async (password) => {
    set({ isLoading: true, error: null });
    try {
      await apiClient.updatePassword(password);
      set({ isLoading: false });
    } catch (error: any) {
      set({ error: toVietnameseAuthError(error.message) || 'Không thể cập nhật mật khẩu', isLoading: false });
      throw error;
    }
  },

  logout: async () => {
    const currentUser = useAuthStore.getState().user;
    if (currentUser?.id) {
      await apiClient.disablePushTokens(currentUser.id).catch(() => undefined);
    }
    await apiClient.logout();
    set({ user: null, token: null, isAuthenticated: false, error: null });
  },

  setUser: (user) => set({ user, isAuthenticated: !!user }),
  setToken: (token) => set({ token, isAuthenticated: !!token }),
  setError: (error) => set({ error }),
  setLoading: (isLoading) => set({ isLoading }),

  restoreSession: (user, token) => {
    set({ user, token, isAuthenticated: true, isLoading: false, isSessionRestored: true, error: null });
  },
}));
